local OIlI0l0OIOO=17
local OlIIllOl0IO=69
local OlII0Ol0OII="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local function OIIllIllIlI(d)
    d=(d or ""):gsub("%s+","")
    d=d:gsub("[^"..OlII0Ol0OII.."=]","")
    return (d:gsub(".",function(x)
        if x=="=" then return "" end
        local r,f="",(OlII0Ol0OII:find(x,1,true)-1)
        for i=6,1,-1 do
            r=r..(f%2^i-f%2^(i-1)>0 and "1" or "0")
        end
        return r
    end):gsub("%d%d%d?%d?%d?%d?%d?%d?",function(x)
        if #x~=8 then return "" end
        local c=0
        for i=1,8 do
            if x:sub(i,i)=="1" then c=c+2^(8-i) end
        end
        return string.char(c)
    end))
end
local function OlOlOIIOIOI(a,b)
    local r,m=0,1
    while a>0 or b>0 do
        local aa=a%2
        local bb=b%2
        if aa~=bb then r=r+m end
        a=(a-aa)/2
        b=(b-bb)/2
        m=m*2
    end
    return r
end
local OOOIO0lOOOO=O000OO000OI:gsub("[^A-Za-z0-9+/=]","")
OOOIO0lOOOO=string.reverse(OOOIO0lOOOO)
local OlI0IIOO0lO=OIIllIllIlI(OOOIO0lOOOO)
local OOIOlIOlO0O={}
for OIOOIIOI0Ol=1,#OlI0IIOO0lO do
    local Ol0IIlI0lIl=OlI0IIOO0lO:byte(OIOOIIOI0Ol)
    local Ol0IOO0OlIl=(Ol0IIlI0lIl-((OlIIllOl0IO+OIOOIIOI0Ol)%256))%256
    OOIOlIOlO0O[OIOOIIOI0Ol]=string.char(OlOlOIIOIOI(Ol0IOO0OlIl,OIlI0l0OIOO))
end
local OlOOlO0OllI=table.concat(OOIOlIOlO0O)
local O0ll0lIlOll=loadstring or load
local OOIlOOll0OI,OO0OllOl0lO=O0ll0lIlOll(OlOOlO0OllI)
if not OOIlOOll0OI then error(OO0OllOl0lO) end
